SELECT 'Old Scales' AS leader_name, COUNT(*) AS leader_count
FROM factions
WHERE leader_name = 'Old Scales';

SELECT unit_id
FROM unit_faction_relationships
WHERE faction_id = 1;

SELECT COUNT(unit_id) AS units_with_attribute_0
FROM unit_attributes
WHERE attribute_id = 0;

SELECT report_text
FROM battle_reports
WHERE report_rating > 7;

SELECT faction_id, COUNT(unit_id) AS unit_count
FROM unit_faction_relationships
GROUP BY faction_id;

SELECT session_date 
FROM game_sessions 
ORDER BY session_date ASC;

SELECT report_text
FROM battle_reports
WHERE report_id = 1;
